import os
from pathlib import Path

def delete_uploaded_file(filename: str, uploads_dir: str = 'uploads') -> bool:
    """
    Delete a file from the uploads directory.

    Args:
        filename: The name of the file to delete.
        uploads_dir: Directory containing uploaded files.

    Returns:
        True if the file was deleted, False if it did not exist.

    Raises:
        ValueError: If the filename attempts path traversal.
        OSError: For system-level file deletion errors.
    """
    base_dir = Path(uploads_dir).resolve()
    safe_name = os.path.basename(filename)
    target_path = (base_dir / safe_name).resolve()

    if base_dir != target_path.parent:
        raise ValueError("Invalid filename.")

    if target_path.exists():
        target_path.unlink()
        return True

    return False